/*****************************************************************************************************
 **** @defgroup: void font_get_chinese_characters_array(uint8_t *font, uint8_t *buff, uint8_t size)
 **** @brief   : 查找一个汉字的字符集
 **** @param    {uint8_t*} font    汉字
 **** @param    {uint8_t*} buff    字符集存放地址
 **** @param    {uint8_t}  size    字体大小 16/24/32/64
 **** @return   {*}
******************************************************************************************************/
void font_get_chinese_characters_array(uint8_t *font, uint8_t *buff, uint8_t size)
{
    uint16_t length = 0;
    uint16_t i, j;

    switch (size)
    {
#ifdef Font_16
    case Font_16:
#ifdef Font_16_USING
        length = sizeof(font_16_array) / sizeof(_font_16_type);
        for (i = 0; i < length; i++)
        {
            if ((*font == font_16_array[i].font[0]) && (*(font + 1) == font_16_array[i].font[1]))
            {
                for (j = 0; j < 32; j++)
                    *buff++ = font_16_array[i].array[j];
                return;
            }
        }
#endif
        for (j = 0; j < 32; j++)
            *buff++ = 0XFF;
        break;
#endif

#ifdef Font_24
    case Font_24:
#ifdef Font_24_USING
        length = sizeof(font_24_array) / sizeof(_font_24_type);
        for (i = 0; i < length; i++)
        {
            if ((*font == font_24_array[i].font[0]) && (*(font + 1) == font_24_array[i].font[1]))
            {
                for (j = 0; j < 72; j++)
                    *buff++ = font_24_array[i].array[j];
                return;
            }
        }
#endif
        for (j = 0; j < 72; j++)
            *buff++ = 0XFF;
        break;
#endif

#ifdef Font_32
    case Font_32:
#ifdef Font_32_USING
        length = sizeof(font_32_array) / sizeof(_font_32_type);
        for (i = 0; i < length; i++)
        {
            if ((*font == font_32_array[i].font[0]) && (*(font + 1) == font_32_array[i].font[1]))
            {
                for (j = 0; j < 128; j++)
                    *buff++ = font_32_array[i].array[j];
                return;
            }
        }
#endif
        for (j = 0; j < 128; j++)
            *buff++ = 0XFF;
        break;
#endif

#ifdef Font_48
    case Font_48:
#ifdef Font_48_USING
        length = sizeof(font_48_array) / sizeof(_font_48_type);
        for (i = 0; i < length; i++)
        {
            if ((*font == font_48_array[i].font[0]) && (*(font + 1) == font_48_array[i].font[1]))
            {
                for (j = 0; j < 288; j++)
                    *buff++ = font_48_array[i].array[j];
                return;
            }
        }
#endif
        for (j = 0; j < 288; j++)
            *buff++ = 0XFF;
        break;
#endif

    default:
        break;
    }
}

